<template><view class="page"><view class="card"><view class="row" @click="about">关于我们</view><view class="row" @click="contact">联系我们</view><view class="row" @click="clear">清除缓存</view><view class="row danger-text" @click="logoutNow">退出登录</view></view></view></template><script setup lang="ts">import { logout } from '@/services/auth';function about(){uni.showModal({title:'关于我们',content:'酒水分销商城一期'})}function contact(){uni.showModal({title:'联系我们',content:'请通过小程序客服入口联系'})}function clear(){uni.clearStorageSync();uni.showToast({title:'已清除',icon:'success'})}async function logoutNow(){await logout();uni.switchTab({url:'/pages/index/index'})}</script><style scoped lang="scss">.page{min-height:100vh;background:#f6f1e8;color:#24170c}.card{background:#fff;margin:20rpx;padding:0 28rpx;border-radius:16rpx}.row{height:96rpx;line-height:96rpx;border-bottom:1rpx solid #eee7db}.danger-text{color:#d64535}</style>
